use strict;
use warnings;

sub gcd {
    my ($a, $b) = @_;
    while ($b != 0) {
        ($a, $b) = ($b, $a % $b);
    }
    return $a;
}

sub lcm {
    my ($a, $b) = @_;
    return ($a * $b) / gcd($a, $b);
}

my ($num1, $num2) = (48, 18);

print "Sayilar: $num1 ve $num2\n";
print "EBOB (GCD): " . gcd($num1, $num2) . "\n";
print "EKOK (LCM): " . lcm($num1, $num2) . "\n";

# Birden fazla cift icin tablo
print "\nFarkli sayi ciftleri:\n";
my @pairs = ([12, 18], [7, 13], [100, 75], [24, 36]);

foreach my $pair (@pairs) {
    my ($a, $b) = @$pair;
    print "GCD($a,$b) = " . gcd($a, $b) . ", LCM($a,$b) = " . lcm($a, $b) . "\n";
}
